#include <stdio.h>
#include <stdint.h>
const long long MOD = 998244353LL;
long long modpow(long long a,long long e){long long r=1%MOD;while(e){if(e&1)r=r*a%MOD;a=a*a%MOD;e>>=1;}return r;}
int main(){
    long long N; if(scanf("%lld",&N)!=1) return 0;
    long long sum=0;
    for(long long i=1;i<=N;i++){
        long long odd=2*i-1;
        sum = (sum + modpow(odd, MOD-2)) % MOD;
    }
    long long ans = (2 * sum) % MOD;
    printf("%lld\n", ans);
    return 0;
}

